(1, '成都市', '四川省', '510100', 104.066541, 30.572269, 12, '/mock-images/city/chengdu.jpg', '兼具市井烟火、历史文化和休闲生活节奏的西南热门旅游城市。', 3.0, 98, 1, 1, '2026-04-30 12:00:00', '2026-04-30 12:00:00'),
(2, '西安市', '陕西省', '610100', 108.939770, 34.341574, 11, '/mock-images/city/xian.jpg', '兼具十三朝古都底蕴和夜游氛围的热门历史文化旅游城市。', 3.0, 95, 2, 1, '2026-04-30 12:00:00', '2026-04-30 12:00:00');
