INSERT INTO spot (id, city_id, spot_name, spot_type, lng, lat, address, amap_poi_id, cover_url, summary, description, recommend_reason, travel_guide, opening_hours, ticket_info, suggested_duration, best_time, recommend_score, hot_score, suitable_crowd, is_free, is_indoor, is_night, is_rainy_day, subway_friendly, first_visit, sort_order, status, created_at, updated_at) VALUES
(101, 1, '宽窄巷子', 'history', 104.056295, 30.669429, '四川省成都市青羊区长顺街附近', 'B001', '/mock-images/chengdu/kuanzhai.jpg', '由宽巷子、窄巷子、井巷子组成的历史文化街区，适合初到成都感受慢生活。', '街区尺度友好，步行体验好，适合作为成都城市漫游第一站。', '交通便利、游览门槛低，适合作为成都城市漫游的第一站。', '建议从地铁宽窄巷子站出站后步行进入主街区，傍晚更适合拍照和逛街。', '全天开放', '免费', 150, '下午至傍晚', 4.8, 96, '首次来成都游客、情侣、城市漫游爱好者', 1, 0, 0, 0, 1, 1, 1, 1, '2026-04-30 12:00:00', '2026-04-30 12:00:00'),
(102, 1, '武侯祠', 'history', 104.047255, 30.642047, '四川省成都市武侯区武侯祠大街231号', 'B002', '/mock-images/chengdu/wuhouci.jpg', '纪念诸葛亮、刘备及蜀汉英雄人物的历史文化景区。', '三国文化主题集中，适合和锦里组合成一条半日路线。', '三国文化主题明确，适合与锦里串联游玩。', '建议上午先逛武侯祠，再步行前往锦里，减少排队和暴晒体验。', '09:00-18:00', '需购票', 120, '上午', 4.7, 92, '历史文化爱好者、亲子家庭', 0, 0, 0, 0, 1, 1, 2, 1, '2026-04-30 12:00:00', '2026-04-30 12:00:00'),
(103, 1, '锦里古街', 'food', 104.048049, 30.642592, '四川省成都市武侯区武侯祠大街231号附1号', 'B003', '/mock-images/chengdu/jinli.jpg', '靠近武侯祠的仿古商业街，夜间灯光和小吃氛围突出。', '夜游氛围强，适合拍照和边走边吃。', '适合夜游和小吃打卡，可与武侯祠安排在同一条路线。', '建议傍晚进入古街，避开正午人流并衔接夜游体验。', '全天开放', '免费', 90, '傍晚至夜间', 4.6, 90, '首次来成都游客、夜游用户、美食爱好者', 1, 0, 1, 0, 1, 0, 3, 1, '2026-04-30 12:00:00', '2026-04-30 12:00:00'),
(104, 1, '成都大熊猫繁育研究基地', 'family', 104.145706, 30.739879, '四川省成都市成华区熊猫大道1375号', 'B004', '/mock-images/chengdu/panda-base.jpg', '以大熊猫保护、繁育和科普展示为核心的成都代表性景点。', '辨识度高、亲子友好，是成都极具代表性的必游点位。', '辨识度高，适合亲子和首次来成都的游客。', '建议早上尽早入园，熊猫更活跃，园区面积较大需要预留足够步行时间。', '07:30-18:00', '需购票', 180, '上午', 4.9, 99, '亲子家庭、首次来成都游客', 0, 0, 0, 0, 0, 1, 4, 1, '2026-04-30 12:00:00', '2026-04-30 12:00:00'),
(105, 1, '杜甫草堂博物馆', 'museum', 104.028480, 30.659765, '四川省成都市青羊区青华路37号', 'B005', '/mock-images/chengdu/dufu-cottage.jpg', '以杜甫成都故居为核心的园林式博物馆，环境安静，文化氛围浓厚。', '园林体验和诗词文化结合，适合慢节奏深度游。', '适合历史文化和诗词主题游览，也适合雨天慢逛。', '建议与浣花溪公园串联安排，雨天可优先选择室内展陈区域。', '09:00-18:00', '需购票', 120, '上午或下午', 4.6, 88, '历史文化爱好者、雨天出游客群', 0, 1, 0, 1, 0, 0, 5, 1, '2026-04-30 12:00:00', '2026-04-30 12:00:00'),
(201, 2, '陕西历史博物馆', 'museum', 108.954260, 34.221954, '陕西省西安市雁塔区小寨东路91号', 'X001', '/mock-images/xian/shaanxi-history-museum.jpg', '馆藏体系完整，是理解西安历史脉络的重要起点。', '文物密度高，适合作为西安历史线第一站。', '适合首次来西安建立城市历史认知。', '建议提前预约门票，优先安排在上午以保证观展体力。', '08:30-18:00', '免费需预约', 180, '上午', 4.9, 97, '首次来西安游客、历史爱好者', 1, 1, 1, 1, 1, 1, 1, 1, '2026-04-30 12:00:00', '2026-04-30 12:00:00'),
(202, 2, '大雁塔', 'landmark', 108.960747, 34.222668, '陕西省西安市雁塔区芙蓉东路3号', 'X002', '/mock-images/xian/dayanta.jpg', '西安地标性古建筑，与周边夜游区域联动性强。', '地标属性强，白天和夜晚体验差异明显。', '适合与大唐不夜城组成夜游路线。', '建议下午到傍晚游览，便于衔接北广场喷泉和夜景。', '08:30-18:00', '需购票', 120, '下午至夜间', 4.8, 95, '首次来西安游客、情侣', 0, 0, 1, 0, 1, 1, 2, 1, '2026-04-30 12:00:00', '2026-04-30 12:00:00'),
(203, 2, '大唐不夜城', 'night', 108.967537, 34.215366, '陕西省西安市雁塔区慈恩路46号', 'X003', '/mock-images/xian/datang-everbright-city.jpg', '大型步行夜游街区，适合夜景打卡和表演体验。', '夜游氛围突出，适合安排在一日行程收尾。', '夜景、演艺和城市氛围兼具。', '建议日落后进入，关注演艺时间并预留步行时间。', '全天开放', '免费', 150, '夜间', 4.8, 96, '年轻游客、夜游用户、情侣', 1, 0, 1, 0, 1, 0, 3, 1, '2026-04-30 12:00:00', '2026-04-30 12:00:00'),
(204, 2, '西安城墙', 'history', 108.946995, 34.266281, '陕西省西安市碑林区南大街', 'X004', '/mock-images/xian/city-wall.jpg', '保存完整的古城墙体系，适合骑行俯瞰老城格局。', '兼具历史价值和城市视野，游玩方式灵活。', '适合想把西安古城格局看得更清楚的游客。', '建议选择南门或永宁门段进入，傍晚骑行体验更舒适。', '08:00-22:00', '需购票', 180, '傍晚', 4.7, 91, '历史文化爱好者、摄影用户', 0, 0, 0, 0, 1, 1, 4, 1, '2026-04-30 12:00:00', '2026-04-30 12:00:00');
